class Solution:
    def totalFruit(self, fruits):
        best = 0
        n = len(fruits)
        for i in range(n):
            seen = {}
            for j in range(i, n):
                f = fruits[j]
                seen[f] = seen.get(f, 0) + 1
                if len(seen) > 2:
                    break
                best = max(best, j - i + 1)
        return best

