class Solution:
    def totalFruit(self, fruits):
        from collections import defaultdict
        cnt = defaultdict(int)
        left = 0
        best = 0
        for right, f in enumerate(fruits):
            cnt[f] += 1
            while len(cnt) > 2:
                cnt[fruits[left]] -= 1
                if cnt[fruits[left]] == 0:
                    del cnt[fruits[left]]
                left += 1
            best = max(best, right - left + 1)
        return best

